#include<bits/stdc++.h>
using namespace std;
char a[1005][20];
char b[1005][20];
int c[1005],d[1005],e[1005];
int main()
{
    int n,m;
    scanf("%d%d",&m,&n);
	for(int i=1;i<=m;i++)
    {
        scanf("%s",b[i]);
        d[i]=strlen(b[i]);
    }
    for(int i=1;i<=n;i++)
    {
        scanf("%d%s",&c[i],a[i]);
    }
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++)
        {
            int flag=0;
            for(int k=0;k<=c[i]-1;k++)
            {
            	if(c[i]>d[j])
            	{
            		break;
				}
                if(b[j][d[j]-c[i]+k]==a[i][k])
                {
                    flag=1;
                }
                else
                {
                    flag=0;
                    break;
                }
            }
            if(flag==1)
            {
                e[i]++;
            }
        }
    }
    for(int i=1;i<=n;i++)
    {
        printf("%d\n",e[i]);
    }
    return 0;
}
